esqlQuery.esql:
FROM logs-nginx.error.otel-*
// Filter to severe log entries only
| WHERE log.level IN ("error", "crit", "alert", "emerg")
// Count error entries per host
| STATS error_count = COUNT(*) BY host.name
// Alert when error count exceeds threshold in the time window
// Adjust threshold based on expected baseline error volume
| WHERE error_count > 50
| SORT error_count DESC
| LIMIT 10
